            flex-shrink: 0;
            text-transform: uppercase;
            letter-spacing: 0.3px;
        }

        .delete-btn:hover {
            background: var(--danger);
            color: white;
            border-color: var(--danger);
            transform: scale(1.06);
        }

        .empty-state {
            text-align: center;
            color: var(--text-secondary);
            padding: 60px 20px;
            font-size: 15px;
        }

        .empty-state-icon {
            font-size: 72px;
            margin-bottom: 20px;
            opacity: 0.5;
            animation: float 3s ease-in-out infinite;
        }

        @keyframes float {
            0%, 100% { transform: translateY(0px); }
            50% { transform: translateY(-12px); }
        }

        .stats-grid {
            display: grid;
            grid-template-columns: repeat(3, 1fr);
            gap: 16px;
        }

        .stat-card {
            padding: 24px;
            background: linear-gradient(135deg, var(--bg-light) 0%, rgba(99, 102, 241, 0.06) 100%);
            border-radius: 16px;
            border: 1.5px solid var(--border);
            transition: all 0.3s ease;
            position: relative;
            overflow: hidden;
        }

        .stat-card::before {
            content: '';
            position: absolute;
            top: 0;
            left: 0;
            right: 0;
            height: 3px;
            background: linear-gradient(90deg, var(--primary) 0%, var(--accent) 100%);
            opacity: 0;
            transition: opacity 0.3s ease;
        }

        .stat-card:hover {
            transform: translateY(-4px);
            box-shadow: var(--shadow-md);
            border-color: var(--primary);
        }

        .stat-card:hover::before {
            opacity: 1;
        }

        .stat-number {
            display: block;
            font-size: 36px;
            font-weight: 900;
            background: linear-gradient(135deg, var(--primary) 0%, var(--accent) 100%);
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;
            background-clip: text;
            margin-bottom: 8px;
            letter-spacing: -1px;
        }

        .stat-label {
            font-size: 11px;
            color: var(--text-secondary);
            font-weight: 800;
            text-transform: uppercase;
            letter-spacing: 0.6px;
        }

        @media (max-width: 900px) {
            .wrapper {
                flex-direction: column;
            }

            .sidebar {
                width: 100%;
                border-right: none;
                border-bottom: 1px solid var(--border);
                padding: 24px;
                flex-direction: row;
                gap: 24px;
                align-items: center;
            }

            .sidebar-section {
                flex-direction: row;
                gap: 8px;
            }

            .main-content {
                padding: 32px 24px;
            }

            .stats-grid {
                grid-template-columns: repeat(2, 1fr);
            }
        }

        @media (max-width: 600px) {
            .sidebar {
                flex-direction: column;
                gap: 16px;
            }

            .main-content {
                padding: 24px 16px;
                gap: 24px;
            }

            .top-bar {
                flex-direction: column;
                align-items: flex-start;
            }

            .top-bar-left h1 {
                font-size: 28px;
            }

            .input-group {
                flex-direction: column;
            }

            .add-btn {
                width: 100%;
            }

            .stats-grid {
                grid-template-columns: 1fr;
            }

            .sidebar-item {
                font-size: 13px;
                padding: 10px 14px;
            }
        }
    </style>
</head>
<body>
    <div class="wrapper">
        <div class="sidebar">
            <div class="logo">✨ Tasks</div>

            <div class="sidebar-section">
                <div class="sidebar-label">Views</div>
                <div class="sidebar-item active" onclick="filterTasks('all')">
                    <span>📋</span> All Tasks
                </div>
                <div class="sidebar-item" onclick="filterTasks('active')">
                    <span>⚡</span> Active
                </div>
                <div class="sidebar-item" onclick="filterTasks('completed')">
                    <span>✅</span> Completed
                </div>
            </div>
        </div>

        <div class="main-content">
            <div class="top-bar">
                <div class="top-bar-left">
                    <h1>Your Tasks</h1>
                    <p>Stay focused and productive</p>
                </div>
                <button class="theme-toggle" id="themeToggle" title="Toggle dark mode">🌙</button>
            </div>

            <div class="input-section">
                <label class="input-label">Add New Task</label>
                <div class="input-group">
                    <input 
                        type="text" 
                        id="todoInput" 
                        placeholder="What needs to be done today?"
                        autocomplete="off"
                    >
                    <button class="add-btn" onclick="addTodo()">Add</button>
                </div>
            </div>

            <div class="tasks-container">
                <div class="section-header">
                    <div class="section-title">📋 Tasks</div>
                    <div class="task-count" id="taskCount">0 tasks</div>
                </div>
                <ul class="todo-list" id="todoList"></ul>

                <div id="emptyState" class="empty-state">
                    <div class="empty-state-icon">📭</div>
                    <div>No tasks yet. Create one to get started!</div>
                </div>
            </div>

            <div class="stats-grid">
                <div class="stat-card">
                    <span class="stat-number" id="totalCount">0</span>
                    <span class="stat-label">Total Tasks</span>
                </div>
                <div class="stat-card">
                    <span class="stat-number" id="completedCount">0</span>
                    <span class="stat-label">Completed</span>
                </div>
                <div class="stat-card">
                    <span class="stat-number" id="pendingCount">0</span>
                    <span class="stat-label">Pending</span>
                </div>
            </div>
        </div>
    </div>

    <script>
        const todoInput = document.getElementById('todoInput');
        const todoList = document.getElementById('todoList');
        const emptyState = document.getElementById('emptyState');
        const themeToggle = document.getElementById('themeToggle');
        const taskCount = document.getElementById('taskCount');

        let todos = JSON.parse(localStorage.getItem('todos')) || [];
        let currentFilter = 'all';
        const isDarkMode = localStorage.getItem('darkMode') === 'true';

        if (isDarkMode) {
            document.body.classList.add('dark-mode');
            themeToggle.textContent = '☀️';
        }

        themeToggle.addEventListener('click', () => {
            document.body.classList.toggle('dark-mode');
            const newDarkMode = document.body.classList.contains('dark-mode');
            localStorage.setItem('darkMode', newDarkMode);
            themeToggle.textContent = newDarkMode ? '☀️' : '🌙';
        });

        renderTodos();

        todoInput.addEventListener('keypress', (e) => {
            if (e.key === 'Enter') {
                addTodo();
            }
        });

        function filterTasks(filter) {
            currentFilter = filter;
            document.querySelectorAll('.sidebar-item').forEach(item => {
                item.classList.remove('active');
            });
            event.target.closest('.sidebar-item').classList.add('active');
            renderTodos();
        }

        function addTodo() {
            const text = todoInput.value.trim();

            if (!text) {
                alert('Please enter a task');
                return;
            }

            const todo = {
                id: Date.now(),
                text: text,
                completed: false
            };

            todos.push(todo);
            saveTodos();
            renderTodos();
            todoInput.value = '';
            todoInput.focus();
        }

        function deleteTodo(id) {
            todos = todos.filter(todo => todo.id !== id);
            saveTodos();
            renderTodos();
        }

        function toggleTodo(id) {
            const todo = todos.find(t => t.id === id);
            if (todo) {
                todo.completed = !todo.completed;
                saveTodos();
                renderTodos();
            }
        }

        function renderTodos() {
            todoList.innerHTML = '';

            let filtered = todos;
            if (currentFilter === 'active') {
                filtered = todos.filter(t => !t.completed);
            } else if (currentFilter === 'completed') {
                filtered = todos.filter(t => t.completed);
            }

            if (filtered.length === 0) {
                emptyState.style.display = 'block';
                updateStats();
                taskCount.textContent = '0 tasks';
                return;
            }

            emptyState.style.display = 'none';
            taskCount.textContent = `${filtered.length} task${filtered.length !== 1 ? 's' : ''}`;

            filtered.forEach(todo => {
                const li = document.createElement('li');
                li.className = `todo-item ${todo.completed ? 'completed' : ''}`;

                li.innerHTML = `
                    <input 
                        type="checkbox" 
                        ${todo.completed ? 'checked' : ''}
                        onchange="toggleTodo(${todo.id})"
                    >
                    <span class="todo-text">${escapeHtml(todo.text)}</span>
                    <button class="delete-btn" onclick="deleteTodo(${todo.id})">Delete</button>
                `;

                todoList.appendChild(li);
            });

            updateStats();
        }

        function updateStats() {
            const total = todos.length;
            const completed = todos.filter(t => t.completed).length;
            const pending = total - completed;

            document.getElementById('totalCount').textContent = total;
            document.getElementById('completedCount').textContent = completed;
            document.getElementById('pendingCount').textContent = pending;
        }

        function saveTodos() {
            localStorage.setItem('todos', JSON.stringify(todos));
        }

        function escapeHtml(text) {
            const div = document.createElement('div');
            div.textContent = text;
            return div.innerHTML;
        }
    </script>
</body>
</html>"}

